     1→import { NextResponse } from 'next/server';
     2→import type { NextRequest } from 'next/server';
     3→import { verifyToken } from '@/server/lib/auth/jwt';
     4→
     5→/**
     6→ * 認証が不要なパス
     7→ */
     8→const PUBLIC_PATHS = ['/admin/login', '/api/admin/auth'];
     9→
    10→/**
    11→ * 管理画面の認証チェック
    12→ */
    13→export async function middleware(request: NextRequest) {
    14→  const { pathname } = request.nextUrl;
    15→
    16→  // 管理画面・管理画面APIのパスチェック
    17→  const isAdminPath = pathname.startsWith('/admin');
    18→  const isAdminApiPath = pathname.startsWith('/api/admin');
    19→
    20→  if (!isAdminPath && !isAdminApiPath) {
    21→    return NextResponse.next();
    22→  }
    23→
    24→  // 認証不要パスのチェック
    25→  if (PUBLIC_PATHS.some(path => pathname.startsWith(path))) {
    26→    return NextResponse.next();
    27→  }
    28→
    29→  // JWT トークンの検証
    30→  const token = request.cookies.get('admin_token')?.value;
    31→
    32→  if (!token) {
    33→    return redirectToLogin(request);
    34→  }
    35→
    36→  const payload = await verifyToken(token);
    37→
    38→  if (!payload) {
    39→    return redirectToLogin(request);
    40→  }
    41→
    42→  return NextResponse.next();
    43→}
    44→
    45→/**
    46→ * ログイン画面へリダイレクト
    47→ */
    48→function redirectToLogin(request: NextRequest) {
    49→  const { pathname } = request.nextUrl;
    50→
    51→  // API リクエストの場合は 401 を返す
    52→  if (pathname.startsWith('/api/admin')) {
    53→    return NextResponse.json({ success: false, error: 'Unauthorized' }, { status: 401 });
    54→  }
    55→
    56→  // 管理画面の場合はログイン画面へリダイレクト
    57→  const loginUrl = new URL('/admin/login', request.url);
    58→  return NextResponse.redirect(loginUrl);
    59→}
    60→
    61→export const config = {
    62→  matcher: ['/admin/:path*', '/api/admin/:path*'],
    63→};
    64→

