     1→/**
     2→ * Chat API Route Handler
     3→ * タスク3.1-3.4: 完全統合版
     4→ */
     5→
     6→import { NextRequest } from 'next/server';
     7→import { z } from 'zod';
     8→import { detectPII } from '@/server/lib/validation/pii';
     9→import { searchFiles } from '@/server/lib/gemini/file-search-service';
    10→import { buildSystemPrompt } from '@/server/lib/prompts/template-engine';
    11→import { generateStreamingResponse } from '@/server/lib/gemini/gateway';
    12→import type { ChatRequest, ChatMetadata } from '@/types/chat';
    13→import type { CoreMessage } from 'ai';
    14→import { logger } from '@/server/lib/logger';
    15→
    16→// 会話履歴の最大件数（システムプロンプト除く）
    17→const MAX_HISTORY = 10;
    18→
    19→// 許可するオリジン一覧
    20→const ALLOWED_ORIGINS: string[] = [
    21→  // 本番環境
    22→  'https://wmg2027.jp',
    23→  'https://www.wmg2027.jp',
    24→  // ステージング環境
    25→  'https://develop.wmg2027.jp',
    26→  // チャットボット自身（直接アクセス用）
    27→  'https://wmg2027-ai-chatbot.vercel.app',
    28→  // Preview環境
    29→  'https://wmg2027-chatbot-preview.vercel.app',
    30→];
    31→
    32→// 開発環境では localhost を許可
    33→if (process.env.NODE_ENV === 'development') {
    34→  ALLOWED_ORIGINS.push(
    35→    'http://localhost:3000',
    36→    'http://localhost:4321' // Astro dev server
    37→  );
    38→}
    39→
    40→/**
    41→ * Origin を検証し、許可されていない場合は false を返す
    42→ */
    43→function isOriginAllowed(origin: string | null): boolean {
    44→  // Origin がない場合（同一オリジンリクエスト）は許可
    45→  if (!origin) return true;
    46→  return ALLOWED_ORIGINS.includes(origin);
    47→}
    48→
    49→/**
    50→ * CORS ヘッダーを生成
    51→ */
    52→function getCorsHeaders(origin: string | null): HeadersInit {
    53→  const headers: HeadersInit = {
    54→    'Content-Type': 'application/json',
    55→  };
    56→
    57→  if (origin && ALLOWED_ORIGINS.includes(origin)) {
    58→    headers['Access-Control-Allow-Origin'] = origin;
    59→    headers['Vary'] = 'Origin';
    60→  }
    61→
    62→  return headers;
    63→}
    64→
    65→// Route configuration for Edge Runtime
    66→export const fetchCache = 'force-no-store';
    67→export const revalidate = 0;
    68→export const dynamic = 'force-dynamic';
    69→export const runtime = 'edge';
    70→
    71→// Zod schema for request validation
    72→const ChatMessageSchema = z.object({
    73→  role: z.enum(['user', 'assistant', 'system']),
    74→  // Vercel AI SDK は content: string だが、parts 由来で content が配列になるケースにも備える
    75→  content: z.union([
    76→    z.string().min(1),
    77→    z
    78→      .array(
    79→        z.object({
    80→          type: z.string().optional(),
    81→          text: z.string().optional(),
    82→        })
    83→      )
    84→      .min(1),
    85→  ]),
    86→});
    87→
    88→const ChatRequestSchema = z.object({
    89→  messages: z.array(ChatMessageSchema).min(1),
    90→  locale: z.string().min(1), // IETF BCP 47, 必須
    91→  userAgent: z.string().optional(),
    92→  traceId: z.string().optional(),
    93→});
    94→
    95→/**
    96→ * OPTIONS: プリフライトリクエスト対応
    97→ */
    98→export async function OPTIONS(request: NextRequest) {
    99→  const origin = request.headers.get('origin');
   100→
   101→  if (isOriginAllowed(origin)) {
   102→    return new Response(null, {
   103→      status: 204,
   104→      headers: {
   105→        'Access-Control-Allow-Origin': origin || '*',
   106→        'Access-Control-Allow-Methods': 'POST, OPTIONS',
   107→        'Access-Control-Allow-Headers': 'Content-Type',
   108→        'Access-Control-Max-Age': '86400',
   109→        Vary: 'Origin',
   110→      },
   111→    });
   112→  }
   113→
   114→  return new Response(null, { status: 403 });
   115→}
   116→
   117→export async function POST(request: NextRequest) {
   118→  const startTime = Date.now();
   119→  const origin = request.headers.get('origin');
   120→
   121→  // Origin 検証
   122→  if (!isOriginAllowed(origin)) {
   123→    logger.warn({ origin }, 'Blocked request from unauthorized origin');
   124→    return new Response(JSON.stringify({ error: 'Forbidden' }), {
   125→      status: 403,
   126→      headers: getCorsHeaders(origin),
   127→    });
   128→  }
   129→
   130→  try {
   131→    // Parse and validate request body
   132→    const body = await request.json();
   133→
   134→    // locale が欠落してもデフォルトで日本語にフォールバック
   135→    if (!body.locale) {
   136→      const acceptLanguage = request.headers.get('accept-language') || '';
   137→      body.locale = acceptLanguage.startsWith('en')
   138→        ? 'en'
   139→        : acceptLanguage.startsWith('zh')
   140→          ? 'zh'
   141→          : acceptLanguage.startsWith('ko')
   142→            ? 'ko'
   143→            : 'ja';
   144→    }
   145→
   146→    // parts 形式の content を文字列に正規化
   147→    if (Array.isArray(body.messages)) {
   148→      body.messages = body.messages.map((m: any) => ({
   149→        ...m,
   150→        content: normalizeContent(m.content),
   151→      }));
   152→    }
   153→
   154→    const validationResult = ChatRequestSchema.safeParse(body);
   155→
   156→    if (!validationResult.success) {
   157→      return new Response(
   158→        JSON.stringify({ error: 'Invalid request format', details: validationResult.error.errors }),
   159→        { status: 400, headers: getCorsHeaders(origin) }
   160→      );
   161→    }
   162→
   163→    const chatRequest: ChatRequest = validationResult.data as ChatRequest;
   164→
   165→    // PII Detection - check all user messages
   166→    for (const message of chatRequest.messages) {
   167→      if (message.role === 'user') {
   168→        const piiResult = detectPII(message.content);
   169→        if (piiResult.found) {
   170→          return new Response(
   171→            JSON.stringify({
   172→              error:
   173→                '個人情報が検出されました。メールアドレス、電話番号、住所などの個人情報は入力しないでください。',
   174→              pii_type: piiResult.type,
   175→            }),
   176→            { status: 422, headers: getCorsHeaders(origin) }
   177→          );
   178→        }
   179→      }
   180→    }
   181→
   182→    // Generate request metadata
   183→    const metadata: ChatMetadata = {
   184→      requestId: crypto.randomUUID(),
   185→      timestamp: new Date().toISOString(),
   186→      locale: chatRequest.locale,
   187→      userAgent: chatRequest.userAgent || request.headers.get('user-agent') || undefined,
   188→    };
   189→
   190→    logger.info(
   191→      {
   192→        requestId: metadata.requestId,
   193→        locale: chatRequest.locale,
   194→        messageCount: chatRequest.messages.length,
   195→      },
   196→      'Chat request received'
   197→    );
   198→
   199→    // Get last user message as query
   200→    const lastUserMessage = chatRequest.messages.filter(m => m.role === 'user').pop();
   201→
   202→    if (!lastUserMessage) {
   203→      return new Response(JSON.stringify({ error: 'No user message found' }), {
   204→        status: 400,
   205→        headers: getCorsHeaders(origin),
   206→      });
   207→    }
   208→
   209→    // タスク3.2: File Search統合 - Top3取得
   210→    const searchResult = await searchFiles(lastUserMessage.content);
   211→
   212→    if (!searchResult.success) {
   213→      logger.error(
   214→        {
   215→          requestId: metadata.requestId,
   216→          error: searchResult.error,
   217→        },
   218→        'File search failed'
   219→      );
   220→
   221→      // File Search失敗時はコンテキストなしで応答を生成
   222→      // (ユーザーには一般的な案内を返す)
   223→    }
   224→
   225→    const contexts = searchResult.results;
   226→    logger.info(
   227→      {
   228→        requestId: metadata.requestId,
   229→        contextCount: contexts.length,
   230→      },
   231→      'Retrieved contexts'
   232→    );
   233→
   234→    // タスク3.3: システムプロンプト構築（コンテキスト付き）
   235→    const systemPrompt = buildSystemPrompt(contexts, chatRequest.locale);
   236→
   237→    // 会話履歴を制限（直近N件）+ messages配列構築
   238→    const recentMessages = chatRequest.messages.slice(-MAX_HISTORY);
   239→    const messages: CoreMessage[] = [
   240→      { role: 'system', content: systemPrompt },
   241→      ...recentMessages.map(m => ({
   242→        role: m.role as 'user' | 'assistant',
   243→        content: m.content,
   244→      })),
   245→    ];
   246→
   247→    logger.info(
   248→      {
   249→        requestId: metadata.requestId,
   250→        historyCount: recentMessages.length,
   251→      },
   252→      'Building messages with conversation history'
   253→    );
   254→
   255→    // タスク3.4: Geminiストリーミング統合（会話履歴対応）
   256→    const streamResult = await generateStreamingResponse(messages);
   257→
   258→    const latency = Date.now() - startTime;
   259→    logger.info(
   260→      {
   261→        requestId: metadata.requestId,
   262→        latency,
   263→      },
   264→      'Response sent'
   265→    );
   266→
   267→    // SSEレスポンスとして返す
   268→    return streamResult.toDataStreamResponse();
   269→  } catch (error) {
   270→    logger.error({ error }, 'Chat API error');
   271→
   272→    // フォールバックメッセージ
   273→    if (error instanceof Error && error.message.includes('一時的に利用できません')) {
   274→      return new Response(JSON.stringify({ error: error.message }), {
   275→        status: 503,
   276→        headers: getCorsHeaders(origin),
   277→      });
   278→    }
   279→
   280→    return new Response(JSON.stringify({ error: 'Internal server error' }), {
   281→      status: 500,
   282→      headers: getCorsHeaders(origin),
   283→    });
   284→  }
   285→}
   286→
   287→/**
   288→ * content が配列（parts）で届いた場合にテキストを抽出し結合する
   289→ */
   290→function normalizeContent(content: unknown): string {
   291→  if (typeof content === 'string') return content;
   292→
   293→  if (Array.isArray(content)) {
   294→    const texts = content
   295→      .map(part => (part as { text?: string }).text)
   296→      .filter((t): t is string => typeof t === 'string' && t.length > 0);
   297→    if (texts.length > 0) return texts.join('\n');
   298→  }
   299→
   300→  return ''; // validation で弾かれる
   301→}
   302→

