     1→import { NextRequest, NextResponse } from 'next/server';
     2→import { verifyPassword } from '@/server/lib/auth/password';
     3→import { createToken } from '@/server/lib/auth/jwt';
     4→import type { LoginRequest, LoginResponse } from '@/types/admin';
     5→
     6→/**
     7→ * ログインAPI
     8→ * POST /api/admin/auth
     9→ */
    10→export async function POST(request: NextRequest): Promise<NextResponse<LoginResponse>> {
    11→  try {
    12→    const body = (await request.json()) as LoginRequest;
    13→    const { password } = body;
    14→
    15→    if (!password) {
    16→      return NextResponse.json(
    17→        { success: false, error: 'パスワードを入力してください' },
    18→        { status: 400 }
    19→      );
    20→    }
    21→
    22→    // パスワード検証
    23→    const isValid = verifyPassword(password);
    24→
    25→    if (!isValid) {
    26→      return NextResponse.json(
    27→        { success: false, error: 'パスワードが正しくありません。再度お試しください。' },
    28→        { status: 401 }
    29→      );
    30→    }
    31→
    32→    // JWT トークン生成
    33→    const token = await createToken();
    34→
    35→    // HttpOnly Cookie に JWT をセット
    36→    const response = NextResponse.json({ success: true });
    37→    response.cookies.set('admin_token', token, {
    38→      httpOnly: true,
    39→      secure: process.env.NODE_ENV === 'production',
    40→      sameSite: 'lax',
    41→      maxAge: parseInt(process.env.JWT_EXPIRES_IN || '3600', 10),
    42→      path: '/',
    43→    });
    44→
    45→    return response;
    46→  } catch (error) {
    47→    console.error('Login error:', error);
    48→    return NextResponse.json(
    49→      {
    50→        success: false,
    51→        error: 'ログイン処理中にエラーが発生しました。しばらくしてからお試しください。',
    52→      },
    53→      { status: 500 }
    54→    );
    55→  }
    56→}
