     1→/**
     2→ * URL管理API - 一覧取得・登録
     3→ * Sprint1 管理画面開発
     4→ *
     5→ * GET: File Search Storeから source_type: web のドキュメントを取得（自動同期）
     6→ * POST: 新しいURLを登録してクロール実行
     7→ */
     8→
     9→import 'server-only';
    10→import { NextRequest, NextResponse } from 'next/server';
    11→import fs from 'fs/promises';
    12→import fsSync from 'fs';
    13→import path from 'path';
    14→import type {
    15→  AdminApiResponse,
    16→  UrlsResponseData,
    17→  CreateUrlRequest,
    18→  CrawlTarget,
    19→  CrawlStatus,
    20→} from '@/types/admin';
    21→import { crawlUrl } from '@/../scripts/data-upload/lib/web-crawler';
    22→import {
    23→  uploadToFileStore,
    24→  updateManifest,
    25→  type FileMetadata,
    26→} from '@/../scripts/data-upload/lib/file-uploader';
    27→
    28→/**
    29→ * Vercel環境かどうかを判定
    30→ */
    31→const isVercel = process.env.VERCEL === '1';
    32→
    33→/**
    34→ * 環境に応じたcrawl-targetsファイルパスを取得
    35→ */
    36→function getCrawlTargetsPath(): string {
    37→  const storeName = process.env.FILE_SEARCH_STORE_NAME || '';
    38→  const isStaging = storeName.includes('staging');
    39→  const fileName = isStaging ? 'crawl-targets-staging.json' : 'crawl-targets.json';
    40→  return path.join(process.cwd(), 'data', fileName);
    41→}
    42→
    43→/**
    44→ * 環境に応じたmanifestファイルパスを取得
    45→ */
    46→function getManifestPath(): string {
    47→  const storeName = process.env.FILE_SEARCH_STORE_NAME || '';
    48→  const isStaging = storeName.includes('staging');
    49→  const fileName = isStaging ? 'file-store-manifest-staging.json' : 'file-store-manifest.json';
    50→  return path.join(process.cwd(), 'data', fileName);
    51→}
    52→
    53→interface CrawlTargetsData {
    54→  version: string;
    55→  updated_at: string;
    56→  targets: CrawlTarget[];
    57→}
    58→
    59→/**
    60→ * crawl-urls.csvからカテゴリー→URLのマッピングを読み込み
    61→ */
    62→function loadUrlMapping(): Map<string, string> {
    63→  const mapping = new Map<string, string>();
    64→
    65→  try {
    66→    const storeName = process.env.FILE_SEARCH_STORE_NAME || '';
    67→    const isStaging = storeName.includes('staging');
    68→    const fileName = isStaging ? 'crawl-urls-staging.csv' : 'crawl-urls.csv';
    69→    const csvPath = path.join(process.cwd(), 'data', fileName);
    70→
    71→    if (!fsSync.existsSync(csvPath)) {
    72→      // ステージング用がなければ通常版を試す
    73→      const fallbackPath = path.join(process.cwd(), 'data', 'crawl-urls.csv');
    74→      if (!fsSync.existsSync(fallbackPath)) {
    75→        return mapping;
    76→      }
    77→      const content = fsSync.readFileSync(fallbackPath, 'utf-8');
    78→      parseUrlCsv(content, mapping);
    79→    } else {
    80→      const content = fsSync.readFileSync(csvPath, 'utf-8');
    81→      parseUrlCsv(content, mapping);
    82→    }
    83→  } catch (error) {
    84→    console.error('[Admin URLs API] Failed to load URL mapping:', error);
    85→  }
    86→
    87→  return mapping;
    88→}
    89→
    90→function parseUrlCsv(content: string, mapping: Map<string, string>): void {
    91→  const lines = content.split('\n').filter(line => line.trim());
    92→  // Skip header
    93→  for (let i = 1; i < lines.length; i++) {
    94→    const parts = lines[i].split(',').map(p => p.trim());
    95→    if (parts.length >= 2) {
    96→      const url = parts[0];
    97→      const category = parts[1];
    98→      // カテゴリーからURLへのマッピング（大文字小文字無視）
    99→      mapping.set(category.toLowerCase(), url);
   100→    }
   101→  }
   102→}
   103→
   104→/**
   105→ * File Search Storeからドキュメント一覧を取得
   106→ */
   107→async function fetchDocumentsFromStore(apiKey: string, storeName: string): Promise<any[]> {
   108→  const allDocs: any[] = [];
   109→  let pageToken: string | undefined;
   110→
   111→  const fullStoreName = storeName.startsWith('fileSearchStores/')
   112→    ? storeName
   113→    : `fileSearchStores/${storeName}`;
   114→
   115→  do {
   116→    const url = new URL(
   117→      `https://generativelanguage.googleapis.com/v1beta/${fullStoreName}/documents`
   118→    );
   119→    url.searchParams.set('pageSize', '20');
   120→    if (pageToken) {
   121→      url.searchParams.set('pageToken', pageToken);
   122→    }
   123→
   124→    const response = await fetch(url.toString(), {
   125→      method: 'GET',
   126→      headers: {
   127→        'x-goog-api-key': apiKey,
   128→      },
   129→      cache: 'no-store',
   130→    });
   131→
   132→    if (!response.ok) {
   133→      const error = await response.json();
   134→      console.error('[Admin URLs API] API error:', error);
   135→      throw new Error(`API error: ${error.error?.message || 'Unknown error'}`);
   136→    }
   137→
   138→    const data = await response.json();
   139→
   140→    if (data.documents) {
   141→      allDocs.push(...data.documents);
   142→    }
   143→    pageToken = data.nextPageToken;
   144→  } while (pageToken);
   145→
   146→  return allDocs;
   147→}
   148→
   149→/**
   150→ * ドキュメントからメタデータを抽出
   151→ */
   152→function getMetadata(doc: any, key: string): string | undefined {
   153→  return doc.customMetadata?.find((m: any) => m.key === key)?.stringValue;
   154→}
   155→
   156→/**
   157→ * crawl-targetsのステータスを更新（同期処理）
   158→ */
   159→function updateCrawlTargetStatus(
   160→  targetId: string,
   161→  status: CrawlStatus,
   162→  errorMessage?: string
   163→): void {
   164→  if (isVercel) {
   165→    console.log(`[Vercel] Crawl target status update skipped: ${targetId} -> ${status}`);
   166→    return;
   167→  }
   168→
   169→  try {
   170→    const crawlTargetsPath = getCrawlTargetsPath();
   171→    if (!fsSync.existsSync(crawlTargetsPath)) return;
   172→
   173→    const data: CrawlTargetsData = JSON.parse(fsSync.readFileSync(crawlTargetsPath, 'utf-8'));
   174→    const targetIndex = data.targets.findIndex(t => t.id === targetId);
   175→
   176→    if (targetIndex !== -1) {
   177→      data.targets[targetIndex].status = status;
   178→      if (status === 'completed') {
   179→        data.targets[targetIndex].last_crawled_at = new Date().toISOString();
   180→        delete data.targets[targetIndex].error_message;
   181→      }
   182→      if (errorMessage) {
   183→        data.targets[targetIndex].error_message = errorMessage;
   184→      }
   185→      data.updated_at = new Date().toISOString();
