   197→export async function GET(): Promise<NextResponse<AdminApiResponse<UrlsResponseData>>> {
   198→  try {
   199→    const apiKey = process.env.GEMINI_API_KEY;
   200→    if (!apiKey) {
   201→      return NextResponse.json(
   202→        { success: false, error: 'GEMINI_API_KEY not configured' },
   203→        { status: 500 }
   204→      );
   205→    }
   206→
   207→    const storeName = process.env.FILE_SEARCH_STORE_NAME;
   208→    if (!storeName) {
   209→      return NextResponse.json(
   210→        { success: false, error: 'FILE_SEARCH_STORE_NAME not configured' },
   211→        { status: 500 }
   212→      );
   213→    }
   214→
   215→    console.log(`[Admin URLs API] Fetching web documents from File Search Store: ${storeName}`);
   216→
   217→    // File Search Store APIからドキュメント一覧を取得
   218→    const documents = await fetchDocumentsFromStore(apiKey, storeName);
   219→    console.log(`[Admin URLs API] Fetched ${documents.length} documents`);
   220→
   221→    // URLマッピングを読み込み（カテゴリーからURLを復元するため）
   222→    const urlMapping = loadUrlMapping();
   223→    console.log(`[Admin URLs API] Loaded ${urlMapping.size} URL mappings`);
   224→
   225→    // source_type: web のドキュメントをCrawlTarget形式に変換
   226→    const webUrls: CrawlTarget[] = documents
   227→      .filter(doc => {
   228→        const sourceType = getMetadata(doc, 'source_type');
   229→        const isActive = doc.state === 'STATE_ACTIVE';
   230→        return sourceType === 'web' && isActive;
   231→      })
   232→      .map((doc, index) => {
   233→        let url = getMetadata(doc, 'url');
   234→        const category = getMetadata(doc, 'category') || doc.displayName || '';
   235→        const locale = getMetadata(doc, 'locale') || 'ja';
   236→
   237→        // URLメタデータがない場合、カテゴリーからURLを復元
   238→        if (!url && category) {
   239→          url = urlMapping.get(category.toLowerCase()) || '';
   240→        }
   241→
   242→        return {
   243→          id: doc.name, // File Search Store document ID
   244→          url: url || '',
   245→          category,
   246→          locale,
   247→          status: 'completed' as CrawlStatus,
   248→          last_crawled_at: doc.updateTime || doc.createTime,
   249→        };
   250→      })
   251→      // URLが復元できなかったものも含める（削除可能にするため）
   252→      // ただし重複URLは除外（同じURLで複数ドキュメントがある場合は最新のみ）
   253→      .reduce((acc: CrawlTarget[], item) => {
   254→        // URLがあり、既に同じURLが存在する場合はスキップ
   255→        if (item.url && acc.some(existing => existing.url === item.url)) {
   256→          return acc;
   257→        }
   258→        acc.push(item);
   259→        return acc;
   260→      }, []);
   261→
   262→    console.log(`[Admin URLs API] Web URLs: ${webUrls.length}`);
   263→
   264→    return NextResponse.json({
   265→      success: true,
   266→      data: {
   267→        urls: webUrls,
   268→      },
   269→    });
   270→  } catch (error) {
   271→    console.error('[Admin URLs API] GET error:', error);
   272→    return NextResponse.json(
   273→      {
   274→        success: false,
   275→        error: error instanceof Error ? error.message : 'Failed to load URLs',
   276→      },
   277→      { status: 500 }
   278→    );
   279→  }
   280→}
