   139→/**
   140→ * ファイルアップロードAPI
   141→ * POST /api/admin/upload
   142→ *
   143→ * 非同期処理: 即座にレスポンスを返し、バックグラウンドでアップロード
   144→ */
   145→export async function POST(request: NextRequest) {
   146→  try {
   147→    // FormDataからファイルとメタデータを取得
   148→    const formData = await request.formData();
   149→    const file = formData.get('file') as File | null;
   150→    const category = (formData.get('category') as string) || undefined;
   151→    const locale = (formData.get('locale') as string) || 'ja';
   152→    const sourceType = (formData.get('source_type') as 'qa' | 'web') || 'qa';
   153→
   154→    // バリデーション
   155→    if (!file) {
   156→      return NextResponse.json<AdminApiResponse>(
   157→        { success: false, error: 'ファイルが選択されていません' },
   158→        { status: 400 }
   159→      );
   160→    }
   161→
   162→    // ファイルサイズチェック
   163→    if (file.size > MAX_FILE_SIZE) {
   164→      return NextResponse.json<AdminApiResponse>(
   165→        { success: false, error: 'ファイルサイズが大きすぎます（上限: 4.5MB）' },
   166→        { status: 400 }
   167→      );
   168→    }
   169→
   170→    // ファイル拡張子チェック
   171→    const ext = path.extname(file.name).toLowerCase();
   172→    if (!ALLOWED_EXTENSIONS.includes(ext)) {
   173→      return NextResponse.json<AdminApiResponse>(
   174→        {
   175→          success: false,
   176→          error: `対応していないファイル形式です。対応形式: ${ALLOWED_EXTENSIONS.join(', ')}`,
   177→        },
   178→        { status: 400 }
   179→      );
   180→    }
   181→
   182→    // Gemini API キーチェック
   183→    const apiKey = process.env.GEMINI_API_KEY;
   184→    if (!apiKey) {
   185→      console.error('❌ GEMINI_API_KEY環境変数が設定されていません');
   186→      return NextResponse.json<AdminApiResponse>(
   187→        { success: false, error: 'サーバー設定エラー' },
   188→        { status: 500 }
   189→      );
   190→    }
   191→
   192→    // ファイル内容を読み込む
   193→    const arrayBuffer = await file.arrayBuffer();
   194→    let content: string;
   195→
   196→    // Excelファイルの場合は変換処理
   197→    if (['.xlsx', '.xls'].includes(ext)) {
   198→      const xlsx = await import('xlsx');
   199→      const workbook = xlsx.read(arrayBuffer);
   200→      content = '';
   201→
   202→      // 全シートをテキストに変換
   203→      for (const sheetName of workbook.SheetNames) {
   204→        const sheet = workbook.Sheets[sheetName];
   205→        content += `## ${sheetName}\n\n`;
   206→        content += xlsx.utils.sheet_to_csv(sheet);
   207→        content += '\n\n';
   208→      }
   209→    } else {
   210→      // テキストファイルとして読み込み
   211→      const decoder = new TextDecoder('utf-8');
   212→      content = decoder.decode(arrayBuffer);
   213→    }
   214→
   215→    // display_nameを生成（プレフィックスなし、元のファイル名をそのまま使用）
   216→    const displayName = file.name;
   217→    const finalCategory = category || path.basename(file.name, ext);
   218→
