     1→import 'server-only';
     2→import crypto from 'crypto';
     3→
     4→/**
     5→ * Timing-safe password comparison
     6→ * Uses crypto.timingSafeEqual to prevent timing attacks
     7→ * @param input - User provided password
     8→ * @param expected - Expected password from environment
     9→ * @returns true if passwords match
    10→ */
    11→function timingSafeCompare(input: string, expected: string): boolean {
    12→  // Convert strings to buffers for comparison
    13→  const inputBuffer = Buffer.from(input, 'utf8');
    14→  const expectedBuffer = Buffer.from(expected, 'utf8');
    15→
    16→  // If lengths differ, we still need to do a constant-time comparison
    17→  // to avoid leaking length information
    18→  if (inputBuffer.length !== expectedBuffer.length) {
    19→    // Compare against a buffer of the same length as input to maintain timing
    20→    const paddedExpected = Buffer.alloc(inputBuffer.length, 0);
    21→    expectedBuffer.copy(paddedExpected, 0, 0, Math.min(expectedBuffer.length, inputBuffer.length));
    22→    crypto.timingSafeEqual(inputBuffer, paddedExpected);
    23→    return false;
    24→  }
    25→
    26→  return crypto.timingSafeEqual(inputBuffer, expectedBuffer);
    27→}
    28→
    29→/**
    30→ * パスワードを検証
    31→ * 環境変数 ADMIN_PASSWORD と比較して認証を行う
    32→ * タイミング攻撃を防ぐためcrypto.timingSafeEqualを使用
    33→ * @param password - 検証するパスワード
    34→ * @returns 検証結果（true: 成功, false: 失敗）
    35→ */
    36→export function verifyPassword(password: string): boolean {
    37→  const adminPassword = process.env.ADMIN_PASSWORD;
    38→
    39→  if (!adminPassword) {
    40→    console.error('ADMIN_PASSWORD is not set in environment variables');
    41→    return false;
    42→  }
    43→
    44→  return timingSafeCompare(password, adminPassword);
    45→}
