    61→async function fetchDocumentsFromStore(apiKey: string, storeName: string): Promise<any[]> {
    62→  const allDocs: any[] = [];
    63→  let pageToken: string | undefined;
    64→
    65→  // storeNameがフルパスでない場合は追加
    66→  const fullStoreName = storeName.startsWith('fileSearchStores/')
    67→    ? storeName
    68→    : `fileSearchStores/${storeName}`;
    69→
    70→  do {
    71→    const url = new URL(
    72→      `https://generativelanguage.googleapis.com/v1beta/${fullStoreName}/documents`
    73→    );
    74→    url.searchParams.set('pageSize', '20');
    75→    if (pageToken) {
    76→      url.searchParams.set('pageToken', pageToken);
    77→    }
    78→
    79→    const response = await fetch(url.toString(), {
    80→      method: 'GET',
    81→      headers: {
    82→        'x-goog-api-key': apiKey,
    83→      },
    84→      // キャッシュを無効化して常に最新データを取得
    85→      cache: 'no-store',
    86→    });
    87→
    88→    if (!response.ok) {
    89→      const error = await response.json();
    90→      console.error('[Admin Files API] API error:', error);
    91→      throw new Error(`API error: ${error.error?.message || 'Unknown error'}`);
    92→    }
    93→
    94→    const data = await response.json();
    95→
    96→    if (data.documents) {
    97→      allDocs.push(...data.documents);
    98→    }
    99→    pageToken = data.nextPageToken;
   100→  } while (pageToken);

